SELECT a.comname as comName, a.username as userName, a.usercode as userCode, a.groups, a.groupscode as groupsCode, max(a.tjtime) as maxTjTime, sum(ck_jsl) as ckJsl, sum(ck_jsl_wcl) as ckJslWcl, sum(ck_wcl) as ckWcl, sum(ds_tjl) as dsTjl, sum(ds_wcl) as dsWcl, sum(ds_zfl) as dsZfl, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie) as tiaoJie, sum(ja) as ja, sum(zl) as zl FROM acd_dangri_gzl_ry a WHERE a.groups is not null AND a.groupscode not in ('5101701','5101702','5101703') AND a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
AND a.groups like concat('%', #{groups}, '%')
AND a.username like concat('%', #{userName}, '%')
GROUP BY 1,2,3,4,5 ORDER BY comName desc limit #{limit} offset #{offset}

SELECT a.comcode as comCode, a.comname as comName, a.tjdate as tjDate, max(a.tjtime) as maxTjTime, sum(ck_jsl) as ckJsl, sum(ck_jsl_wcl) as ckJslWcl, sum(ck_wcl) as ckWcl, sum(ds_tjl) as dsTjl, sum(ds_wcl) as dsWcl, sum(ds_zfl) as dsZfl, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie) as tiaoJie, sum(ja) as ja, sum(zl) as zl FROM acd_dangri_gzl_bm a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
GROUP BY 1,2,3 ORDER BY comName desc limit #{limit} offset #{offset}

select count(*) from ( SELECT a.comcode, a.comname, a.tjdate FROM acd_dangri_gzl_bm a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
GROUP BY 1,2,3 ) t

SELECT a.comcode as comCode, a.comname as comName, a.tjdate as tjDate, max(a.tjtime) as maxTjTime, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie_zhuyuan) as tiaojieZhuyuan, sum(tiaojie_menzheng) as tiaojieMenzheng, sum(jiean_zhuyuan) as jieanZhuyuan, sum(jiean_mengzheng) as jieanMengzheng FROM acd_dangri_gzl_rs a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
