select tjdate, tjdate as maxTjTime, comcode_sgs, comname_sgs, chakan_zt, cuiding_zt, dingsun_zt, zhifu_zt, zhouqi_zt, zhouqi_wyn, zhouqi_wys from acd_zhouqi_qs where 1 = 1 and tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
